-- ============================================================
-- BHL OMS-TMS-WMS — DỮ LIỆU DEMO BỔ SUNG
-- Bổ sung dữ liệu để demo đầy đủ các chức năng:
--   1. 80% tài xế sẵn sàng (56/70 available)
--   2. Tồn kho tất cả 30 sản phẩm, cả 2 kho
--   3. Thêm trips in_transit + GPS-ready cho bản đồ
--   4. Đối soát (reconciliations + discrepancies)
--   5. Chốt sổ cuối ngày (daily_close_summaries)
--   6. Thêm đơn pending_approval cho kế toán
-- ============================================================

-- ====================
-- 1. DRIVER CHECKINS — 80% sẵn sàng (56 available, 14 off/no-checkin)
-- ====================
INSERT INTO driver_checkins (driver_id, checkin_date, status, reason)
SELECT
  CONCAT('f0000000-0000-0000-0000-', LPAD(n::text, 12, '0'))::uuid,
  CURRENT_DATE,
  'available',
  NULL
FROM generate_series(1, 56) n
ON CONFLICT (driver_id, checkin_date) DO UPDATE SET status = 'available', reason = NULL;

-- 8 tài xế off_duty
INSERT INTO driver_checkins (driver_id, checkin_date, status, reason)
SELECT
  CONCAT('f0000000-0000-0000-0000-', LPAD(n::text, 12, '0'))::uuid,
  CURRENT_DATE,
  'off_duty',
  CASE (n % 3)
    WHEN 0 THEN 'Nghỉ phép'
    WHEN 1 THEN 'Bảo dưỡng xe'
    ELSE 'Nghỉ ốm'
  END
FROM generate_series(57, 64) n
ON CONFLICT (driver_id, checkin_date) DO UPDATE SET status = 'off_duty', reason = EXCLUDED.reason;

-- Drivers 65-70: không checkin (6 người) → hệ thống coi như chưa sẵn sàng

